    }

    if (has(KilobyteSymbol))
    {
        format = format.Replace(KilobyteSymbol, "KB");
        return output(Kilobytes);
    }

    // Correct: case-sensitive check with StringComparison.Ordinal
    if (format.Contains(ByteSymbol, StringComparison.Ordinal))
